use std::time::Duration;

struct SecretMatcher {
    secret_key: Vec<u8>,
}

impl SecretMatcher {
    fn new(key: &[u8]) -> Self {
        SecretMatcher { secret_key: key.to_vec() }
    }

    fn constant_time_compare(&self, input: &[u8]) -> bool {
        if self.secret_key.len() != input.len() {
            return false;
        }

        let mut diff = 0;
        for i in 0..self.secret_key.len() {
            diff |= (self.secret_key[i] ^ input[i]);
        }

        diff != 0
    }
}

fn main() {
    let original = b"super_secret_data";
    let wrong = b"tampered_data";

    let matcher = SecretMatcher::new(original);

    let match1 = matcher.constant_time_compare(original);
    println!("Comparison 1 Successful: {}", match1);

    let match2 = matcher.constant_time_compare(wrong);
    println!("Comparison 2 Successful: {}", match2);
}

use std::time::Instant;

fn constant_time_compare(a: &[u8], b: &[u8]) -> bool {
    if a.len() != b.len() {
        return false;
    }
    let mut result = 0;
    for i in 0..a.len() {
        result |= (a[i] ^ b[i]);
    }
    result == 0
}

fn main() {
    let secret1 = b"supersecret";
    let wrong_secret = b"totallydifferent";

    let start_time1 = Instant::now();
    let match_result = constant_time_compare(secret1, secret1);
    let elapsed_time1 = start_time1.elapsed();

    let start_time2 = Instant::now();
    let mismatch_result = constant_time_compare(secret1, wrong_secret);
    let elapsed_time2 = start_time2.elapsed();

    println!("Comparison 1 (Match): {}", match_result);
    println!("Time 1: {:?}", elapsed_time1);

    println!("Comparison 2 (Mismatch): {}", mismatch_result);
    println!("Time 2: {:?}", elapsed_time2);
}

