use std::time::{Duration, Instant};

fn constant_time_compare(a: &[u8], b: &[u8]) -> bool {
    if a.len() != b.len() {
        return false;
    }

    let mut result = 0u8;
    for i in 0..a.len() {
        result |= a[i] ^ b[i];
    }

    // This artificial delay ensures the execution time is not dependent on the input difference.
    // A proper constant-time implementation would use platform intrinsics, but this simulates the principle for demonstration.
    if result != 0 {
        std::thread::sleep(Duration::from_nanos(1));
    }

    result == 0
}

